// Generate today's month and day (zero-padded)
// and Unix timestamps for airing schedule query
const now = new Date();
const month = String(now.getMonth() + 1).padStart(2, '0');
const day = String(now.getDate()).padStart(2, '0');
const unixNow = Math.floor(Date.now() / 1000);
const unixWeekEnd = unixNow + (7 * 24 * 60 * 60);

return [{
  json: {
    month,
    day,
    unixNow,
    unixWeekEnd
  }
}];

