parameters.jsCode:
const MIN_POPULARITY = 30000;
const PREMIERE_MIN_POPULARITY = 50000;
const EPISODE_MIN_POPULARITY = 30000;
const MAX_EPISODES = 3;

const allItems = $input.all();

let annItems = [];
let anniversaryItems = [];
let airingSchedules = [];
let trendingAnime = [];

for (const item of allItems) {
  const data = item.json;
  if (data.title && data.link && data.pubDate && !data.data) {
    annItems.push(data);
    continue;
  }
  if (data.data?.Page?.airingSchedules?.length > 0) {
    airingSchedules = [...airingSchedules, ...data.data.Page.airingSchedules];
    continue;
  }
  if (data.data?.Page?.media?.length > 0) {
    const media = data.data.Page.media;
    if (media[0]?.trending !== undefined) {
      trendingAnime = [...trendingAnime, ...media];
    } else {
      anniversaryItems = [...anniversaryItems, ...media];
    }
  }
}

// ---- Load 30-day history ----
let recentAnimeIds = new Set();
try {
  const historyData = $('Pass History to Selection').first().json.historyRows || [];
  const thirtyDaysAgo = Date.now() - (30 * 24 * 60 * 60 * 1000);
  for (const row of historyData) {
    if (!row.date || !row.animeId) continue;
    const rowDate = (typeof row.date === 'number' ? new Date((row.date - 25569) * 86400 * 1000) : new Date(row.date)).getTime();
    if (rowDate >= thirtyDaysAgo) {
      recentAnimeIds.add(String(row.animeId));
    }
  }
} catch(e) {
  // Sheet empty or not connected — continue without history
}

// ---- Time helpers ----
const now = new Date();
const todayStart = new Date(now); todayStart.setHours(0,0,0,0);
const todayEnd = new Date(now); todayEnd.setHours(23,59,59,999);
const weekEnd = new Date(todayEnd.getTime() + (6 * 24 * 60 * 60 * 1000));

function airsToday(ep) {
  const d = new Date(ep.airingAt * 1000);
  return d >= todayStart && d <= todayEnd;
}

function airsThisWeek(ep) {
  const d = new Date(ep.airingAt * 1000);
  return d > todayEnd && d <= weekEnd;
}

// ---- Sort trending by popularity ----
const sortedTrending = trendingAnime
  .filter(t => (t.popularity || 0) >= MIN_POPULARITY)
  .sort((a, b) => (b.popularity || 0) - (a.popularity || 0));

// ---- Sort airing by popularity ----
const sortedAiring = airingSchedules
  .filter(ep => ep.media && (ep.media.popularity || 0) >= EPISODE_MIN_POPULARITY)
  .sort((a, b) => (b.media?.popularity || 0) - (a.media?.popularity || 0));

// ---- Map: animeId -> earliest airing time this week ----
// Used to find which trending shows drop this week and when
const weekAiringMap = {};
for (const ep of airingSchedules) {
  if (!ep.media?.id) continue;
  if (!airsThisWeek(ep)) continue;
  if ((ep.media?.popularity || 0) < MIN_POPULARITY) continue;
  const id = ep.media.id;
  if (!weekAiringMap[id] || ep.airingAt < weekAiringMap[id].airingAt) {
    weekAiringMap[id] = ep;
  }
}

const droppingThisWeekIds = new Set(Object.keys(weekAiringMap).map(Number));

// ---- Major news keywords ----
const majorNewsKeywords = [
  'season 2','season 3','season 4','season 5','new season',
  'officially announced','confirmed','greenlit','renewal','returns',
  'final season','movie announced','film announced',
  '10th anniversary','15th anniversary','20th anniversary','25th anniversary'
];
function isMajorNews(headline) {
  const h = headline.toLowerCase();
  return majorNewsKeywords.some(kw => h.includes(kw));
}

let finalStory = null;
let mainStoryAnimeId = null;

// ---- PRIORITY 1: Anime premiering TODAY (Episode 1 or 2 only) ----
for (const ep of sortedAiring) {
  if (!airsToday(ep)) continue;
  if (ep.episode > 2) continue;
  if ((ep.media?.popularity || 0) < PREMIERE_MIN_POPULARITY) continue;

  const anime = sortedTrending.find(t => t.id === ep.media.id) || ep.media;
  finalStory = {
    type: 'premiere_today',
    title: ep.media.title?.english || ep.media.title?.romaji,
    headlineForCaption: `${ep.media.title?.english || ep.media.title?.romaji} — Episode ${ep.episode} premiered today`,
    image: ep.media.coverImage?.extraLarge || anime.bannerImage || null,
    popularity: ep.media.popularity,
    description: anime.description || '',
    animeId: ep.media.id
  };
  mainStoryAnimeId = ep.media.id;
  break;
}

// ---- PRIORITY 2: Very popular continuing episode airing TODAY ----
if (!finalStory) {
  for (const ep of sortedAiring) {
    if (!airsToday(ep)) continue;
    if (ep.episode <= 2) continue;
    if ((ep.media?.popularity || 0) < 75000) continue;

    const anime = sortedTrending.find(t => t.id === ep.media.id) || ep.media;
    finalStory = {
      type: 'airing_today',
      title: ep.media.title?.english || ep.media.title?.romaji,
      romajiTitle: ep.media.title?.romaji || null,
      headlineForCaption: `${ep.media.title?.english || ep.media.title?.romaji} — Episode ${ep.episode} aired this week`,
      image: ep.media.coverImage?.extraLarge || anime.bannerImage || null,
      popularity: ep.media.popularity,
      description: anime.description || '',
      animeId: ep.media.id
    };
    mainStoryAnimeId = ep.media.id;
    break;
  }
}

// ---- PRIORITY 3: Major news about a popular anime ----
if (!finalStory) {
  for (const item of annItems) {
    if (!isMajorNews(item.title || '')) continue;
    const headline = (item.title || '').toLowerCase();
    const matchedAnime = sortedTrending.find(t => {
      const eng = (t.title?.english || '').toLowerCase();
      const rom = (t.title?.romaji || '').toLowerCase();
      return (eng.length > 3 && headline.includes(eng)) ||
             (rom.length > 3 && headline.includes(rom));
    });
    if (matchedAnime && !recentAnimeIds.has(String(matchedAnime.id)) && (matchedAnime.popularity || 0) >= 50000) {
      finalStory = {
        type: 'news',
        title: matchedAnime.title?.english || matchedAnime.title?.romaji,
        romajiTitle: matchedAnime.title?.romaji || null,
        headlineForCaption: item.title,
        image: matchedAnime.coverImage?.extraLarge || matchedAnime.bannerImage || null,
        popularity: matchedAnime.popularity,
        description: item.contentSnippet || '',
        animeId: matchedAnime.id
      };
      mainStoryAnimeId = matchedAnime.id;
      break;
    }
  }
}

// ---- PRIORITY 4: Anniversary / birthday TODAY ----
if (!finalStory) {
  const popularAnniversaries = anniversaryItems
    .filter(a => (a.popularity || 0) >= MIN_POPULARITY)
    .sort((a, b) => (b.popularity || 0) - (a.popularity || 0));
  if (popularAnniversaries.length > 0) {
    const a = popularAnniversaries[0];
    const age = a.startDate?.year ? new Date().getFullYear() - a.startDate.year : 0;
    finalStory = {
      type: 'anniversary',
      title: a.title?.english || a.title?.romaji,
      headlineForCaption: `${a.title?.english || a.title?.romaji} turns ${age} years old today 🎂`,
      image: a.coverImage?.extraLarge || a.bannerImage || null,
      popularity: a.popularity,
      description: a.description || '',
      animeId: a.id
    };
    mainStoryAnimeId = a.id;
  }
}

// ---- PRIORITY 5: Trending anime NOT dropping this week ----
if (!finalStory) {
  const candidate = sortedTrending.find(t => {
    if (recentAnimeIds.has(String(t.id))) return false;
    if (droppingThisWeekIds.has(t.id)) return false;
    return true;
  });

  if (candidate) {
    finalStory = {
      type: 'trending',
      title: candidate.title?.english || candidate.title?.romaji,
      romajiTitle: candidate.title?.romaji || null,
      headlineForCaption: `${candidate.title?.english || candidate.title?.romaji} is the #1 trending anime right now`,
      image: candidate.coverImage?.extraLarge || candidate.bannerImage || null,
      popularity: candidate.popularity,
      description: candidate.description || '',
      animeId: candidate.id
    };
    mainStoryAnimeId = candidate.id;
  }
}

// ---- PRIORITY 6: Fallback — pick trending that drops LATEST in the week ----
// When everything popular drops this week, pick the one furthest away
// so it feels least like a "coming soon" tease
if (!finalStory && sortedTrending.length > 0) {
  // Among trending anime dropping this week, find the one airing latest
  const trendingWithAirTime = sortedTrending
    .filter(t => !recentAnimeIds.has(String(t.id)))
    .map(t => ({
      anime: t,
      airTime: weekAiringMap[t.id]?.airingAt || 0
    }))
    .filter(x => x.airTime > 0)
    .sort((a, b) => b.airTime - a.airTime); // latest airing first

  const pick = trendingWithAirTime.length > 0
    ? trendingWithAirTime[0].anime
    : sortedTrending.find(t => !recentAnimeIds.has(String(t.id))) || sortedTrending[0];

  finalStory = {
    type: 'trending',
    title: pick.title?.english || pick.title?.romaji,
    romajiTitle: pick.title?.romaji || null,
    headlineForCaption: `${pick.title?.english || pick.title?.romaji} — trending on AniList this week`,
    image: pick.coverImage?.extraLarge || pick.bannerImage || null,
    popularity: pick.popularity,
    description: pick.description || '',
    animeId: pick.id
  };
  mainStoryAnimeId = pick.id;
}

// ---- Episode list ----
// Top 3 most popular episodes dropping later this week
// Excludes: main story anime, anything airing TODAY
const episodeList = sortedAiring
  .filter(ep => {
    if (ep.media?.id === mainStoryAnimeId) return false;
    if (airsToday(ep)) return false;
    if (!airsThisWeek(ep)) return false;
    return true;
  })
  .reduce((acc, ep) => {
    if (!acc.find(e => e.media?.id === ep.media?.id)) acc.push(ep);
    return acc;
  }, [])
  .slice(0, MAX_EPISODES)
    .map(ep => {
    const date = new Date(ep.airingAt * 1000);
    const dayName = date.toLocaleDateString('en-US', { weekday: 'short' });
    const month = date.toLocaleDateString('en-US', { month: 'short' });
    const day = date.getDate();
    const hours = date.getHours().toString().padStart(2, '0');
    const minutes = date.getMinutes().toString().padStart(2, '0');
    const title = ep.media?.title?.english || ep.media?.title?.romaji || 'Unknown';
    return dayName + ' ' + month + ' ' + day + ' ' + hours + ':' + minutes + ' — ' + title + ' Ep.' + ep.episode;
  })
  .join('\n');

// ---- Safety: ensure image exists ----
if (finalStory && !finalStory.image) {
  const fallback = sortedTrending.find(t => t.id === mainStoryAnimeId);
  finalStory.image = fallback?.coverImage?.extraLarge || fallback?.bannerImage ||
    sortedTrending[0]?.coverImage?.extraLarge || sortedTrending[0]?.bannerImage || null;
}

return [{
  json: {
    finalStory,
    episodeList: episodeList || 'No episodes this week',
    debug: {
      airingCount: airingSchedules.length,
      trendingCount: trendingAnime.length,
      annCount: annItems.length,
      storyType: finalStory?.type,
      selectedTitle: finalStory?.title,
      episodeListPreview: episodeList,
      recentAnimeCount: recentAnimeIds.size,
      droppingThisWeekCount: droppingThisWeekIds.size
    }
  }
}];

