// ============================================================
// FRAMED — Smart Text Placement
// Uses Cloudinary focal point to pick the best corner
// ============================================================

const cloudinaryInfo = $input.first().json;

let corner = 'bottom-right'; // safe default
let bannerbearGravity = 'SouthEast';
let xOffset = 48;
let yOffset = 48;

try {
  const cropRegion = cloudinaryInfo.g_auto_info?.crop_region;

  if (cropRegion) {
    // Calculate center of the safe (face-avoided) zone
    const safeCenterX = (cropRegion.x1 + cropRegion.x2) / 2;
    const safeCenterY = (cropRegion.y1 + cropRegion.y2) / 2;

    const safeZoneWidth = cropRegion.x2 - cropRegion.x1;
    const safeZoneHeight = cropRegion.y2 - cropRegion.y1;

    // Only use detection if safe zone is large enough to matter
    if (safeZoneWidth >= 0.2 && safeZoneHeight >= 0.15) {
      if (safeCenterX <= 0.5 && safeCenterY >= 0.5) {
        corner = 'bottom-left';
        bannerbearGravity = 'SouthWest';
      } else if (safeCenterX > 0.5 && safeCenterY >= 0.5) {
        corner = 'bottom-right';
        bannerbearGravity = 'SouthEast';
      } else if (safeCenterX <= 0.5 && safeCenterY < 0.5) {
        corner = 'top-left';
        bannerbearGravity = 'NorthWest';
      } else {
        corner = 'top-right';
        bannerbearGravity = 'NorthEast';
      }
    }
  }
} catch (e) {
  // Fallback to bottom-right if detection fails
  corner = 'bottom-right';
  bannerbearGravity = 'SouthEast';
}

return [{
  json: {
    corner,
    bannerbearGravity,
    xOffset,
    yOffset
  }
}];

const story = $('Extract TMDB Image').first().json;
