const yOffset = $('Calculate Text Corner').first().json.yOffset || 48;

const activeSizes = $('Fetch Active Sizes').all()
  .map(item => item.json)
  .filter(row => row.active === 'active');

function cloudinaryUrl(width, height) {
  return `https://res.cloudinary.com/ddlmwfeup/image/upload/w_${width},h_${height},c_fill,g_auto,e_sharpen:150,e_improve,q_95,f_jpg/${publicId}.jpg`;
}

const results = [];

for (const size of activeSizes) {
  const width = parseInt(size.width, 10);
  const height = parseInt(size.height, 10);
  const templateName = size.template_name || size.templateName || size.sizeName;

  results.push({
