function escapeXml(value) {
  return String(value)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&apos;');
}

function wrapLines(text, maxChars) {
  const words = String(text || '').split(/\s+/).filter(Boolean);
  const lines = [];
  let current = '';

  for (const word of words) {
    const candidate = current ? `${current} ${word}` : word;
    if (candidate.length <= maxChars) {
      current = candidate;
    } else {
      if (current) lines.push(current);
      current = word;
    }
  }

  if (current) lines.push(current);
  return lines.length ? lines : [''];
}

function buildTextBlock(text, x, y, width, fontSize, lineHeight, color, anchor = 'middle') {
  const maxChars = Math.max(12, Math.floor(width / (fontSize * 0.58)));
  const lines = wrapLines(text, maxChars);
  const startY = y - ((lines.length - 1) * lineHeight) / 2;
  const textAnchor = anchor === 'start' ? 'start' : anchor === 'end' ? 'end' : 'middle';
  const tspans = lines.map((line, index) => {
    const dy = index === 0 ? 0 : lineHeight;
    return `<tspan x=\

>${tspans}</text>`;
}

const caption = input.caption || '';
const episodeList = input.episodeList || '';
const bandHeight = Math.max(220, Math.round(input.height * 0.26));
const bandY = input.height - bandHeight;
const titleSize = Math.max(48, Math.round(Math.min(input.width, input.height) * 0.056));
const listSize = Math.max(26, Math.round(Math.min(input.width, input.height) * 0.03));
const titleLines = wrapLines(caption, Math.max(16, Math.floor(input.width / (titleSize * 0.48))));
const titleBlockHeight = titleLines.length * Math.round(titleSize * 1.08);
const titleY = bandY + 64 + titleBlockHeight / 2;
const listY = titleY + titleBlockHeight / 2 + 58;

const svg = `<?xml version=\

/>
  ${buildTextBlock(caption, Math.round(input.width / 2), titleY, Math.round(input.width * 0.84), titleSize, Math.round(titleSize * 1.1), '#FFFFFF')}
  ${buildTextBlock(episodeList, Math.round(input.width / 2), listY, Math.round(input.width * 0.78), listSize, Math.round(listSize * 1.2), 'rgba(255,255,255,0.88)')}
</svg>`;

const image_url = `data:image/svg+xml;charset=UTF-8,${encodeURIComponent(svg)}`;

return [{ json: { ...input, svg, image_url } }];

const story = $('Resolve Final Story').first().json;

return [{
