  if (imgs.backdrops && imgs.backdrops.length > 0) {
    const sorted = imgs.backdrops.filter(b=>b.width>b.height).sort((a,b)=>(b.vote_average||0)-(a.vote_average||0));
    const chosen = sorted.filter(b=>!used.includes(b.file_path))[0] || sorted[0];
    if (chosen) { imageUrl='https://image.tmdb.org/t/p/original'+chosen.file_path; backdropPath=chosen.file_path; }
  }
} catch(e) {}
if (!backdropPath && imageUrl) {
  imageUrl = 'https://res.cloudinary.com/ddlmwfeup/image/fetch/c_fill,g_auto:subject,ar_16:9/' + encodeURIComponent(imageUrl);
}
if (!backdropPath && ed.finalStory.tmdbFound) { const m=imageUrl.match(/\/original(\/[^?]+)/); if(m) backdropPath=m[1]; }
return [{ json: { ...ed, finalStory: { ...ed.finalStory, image: imageUrl, backdropPath } } }];

