const subscribers = $input.all().map(item => item.json);
const imageUrl = $('Prepare Sharp Result').first().json.image_url;
const headline = $('Resolve Final Story').first().json.headlineForCaption;
const episodeList = $('Resolve Final Story').first().json.episodeList;

function normalize(value) {
  return String(value ?? '').trim().toLowerCase();
}

function isTruthy(value) {
  return ['true', '1', 'yes', 'y', 'active'].includes(normalize(value));
}

const eligible = subscribers.filter(row => {
  const state = normalize(row.subscription_state);
  const category = normalize(row.category);
  const tier = normalize(row.tier);
  const active = isTruthy(row.active);
  const isPaidTier = tier && tier !== 'free';

  return active && state === 'active' && (category === 'space' || category === 'all') && isPaidTier;
});

return eligible.map(subscriber => {
  const tier = normalize(subscriber.tier);
  return {
    json: {
      chat_id: subscriber.chat_id,
      tier: subscriber.tier,
      category: subscriber.category,
      resolution_mode: tier === 'framed+' ? 'all_sizes' : 'fhd_4k',
      image_url: imageUrl,
      caption: `${headline}\n\n📺 This week's episodes:\n${episodeList}\n\n🖼 Your daily wallpaper — tap & hold to save!\n\nThanks for subscribing to Framed 🎌`
    }
  };
});

