return items.map(item => {
  const errorText = String(item.error?.message ?? item.error ?? '').trim();
  const normalizedError = errorText.toLowerCase();
  const isChatNotFound = normalizedError.includes('chat_not_found') || normalizedError.includes('chat not found');

  return {
    json: {
      sent_at: new Date().toISOString(),
      chat_id: item.chat_id || '',
      tier: item.tier || '',
      category: item.category || '',
      resolution_mode: item.resolution_mode || '',
      status: errorText ? 'failed' : 'delivered',
      error: errorText,
      inactive: isChatNotFound ? 'true' : 'false',
      subscriber_active: isChatNotFound ? 'false' : ''
    }
  };
});

